import React, { useState, useEffect } from 'react';

function loadXLSX() {
  return new Promise((resolve) => {
    if (window.XLSX) { resolve(window.XLSX); return; }
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';
    s.onload = () => resolve(window.XLSX);
    document.head.appendChild(s);
  });
}

const API = 'http://localhost:5000';

export default function AttendanceRecords() {
  const [records,      setRecords]      = useState([]);
  const [sessions,     setSessions]     = useState([]);
  const [session,      setSession]      = useState('default');
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [loading,      setLoading]      = useState(false);
  const [showExport,   setShowExport]   = useState(false);
  const [expSession,   setExpSession]   = useState('all');
  const [expFrom,      setExpFrom]      = useState('');
  const [expTo,        setExpTo]        = useState('');
  const [expLoading,   setExpLoading]   = useState(false);
  const [expPreview,   setExpPreview]   = useState(null);
  const [toast,        setToast]        = useState(null);

  const showToast = (msg, type='success') => { setToast({msg,type}); setTimeout(()=>setToast(null),4000); };

  useEffect(() => {
    fetch(`${API}/api/attendance/sessions`)
      .then(r=>r.json()).then(d=>setSessions(Array.isArray(d)?d:[])).catch(()=>{});
  }, []);

  useEffect(() => {
    setLoading(true);
    fetch(`${API}/api/attendance?sessionId=${session}&date=${selectedDate}`)
      .then(r=>r.json()).then(d=>setRecords(d.records||[]))
      .catch(()=>setRecords([])).finally(()=>setLoading(false));
  }, [session, selectedDate]);

  const exportDailyCSV = () => {
    const hdr  = 'Student ID,Name,Course,Time,Date\n';
    const rows = records.map(r=>`${r.studentId},"${r.name}","${r.course}",${r.time},${r.date}`).join('\n');
    const a    = document.createElement('a');
    a.href     = URL.createObjectURL(new Blob([hdr+rows],{type:'text/csv'}));
    a.download = `attendance_${session}_${selectedDate}.csv`;
    a.click();
  };

  const loadPreview = async () => {
    if (!expFrom || !expTo) { showToast('Select both start and end dates','error'); return; }
    if (expFrom > expTo)    { showToast('Start date must be before end date','error'); return; }
    setExpLoading(true);
    try {
      const r = await fetch(`${API}/api/attendance/export?date_from=${expFrom}&date_to=${expTo}&session=${encodeURIComponent(expSession)}`);
      const d = await r.json();
      if (!r.ok) { showToast(d.error||'Failed','error'); return; }
      setExpPreview(d);
    } catch { showToast('Network error — is the backend running?','error'); }
    finally { setExpLoading(false); }
  };

  /* ── EXCEL EXPORT ── */
  const exportExcel = async () => {
    if (!expPreview?.records?.length) { showToast('No records to export','error'); return; }
    setExpLoading(true);
    try {
      const XLSX = await loadXLSX();
      const wb   = XLSX.utils.book_new();
      const recs = expPreview.records;

      /* all unique sorted dates in range */
      const allDates = [...new Set(recs.map(r=>r.date))].sort();

      /* build student rows: studentId → { name, course, datesMap } */
      const studentsMap = {};
      recs.forEach(r => {
        if (!studentsMap[r.studentId]) {
          studentsMap[r.studentId] = { name: r.name, course: r.course, dates: {} };
        }
        studentsMap[r.studentId].dates[r.date] = '✓';
      });

      /* ── SHEET 1: Attendance Matrix (the main sheet) ── */
      // Header row: Student ID | Name | Course Unit | date1 | date2 | ... | Days Present | Attendance %
      const header = ['Student ID', 'Name', 'Course Unit', ...allDates, 'Days Present', 'Attendance %'];

      const dataRows = Object.entries(studentsMap).map(([sid, s]) => {
        const daysPresent = allDates.filter(d => s.dates[d]).length;
        const pct         = allDates.length ? Math.round((daysPresent / allDates.length) * 100) + '%' : '0%';
        return [
          sid,
          s.name,
          s.course,
          ...allDates.map(d => s.dates[d] || ''),   // ✓ or blank
          daysPresent,
          pct,
        ];
      });

      // Sort rows by name
      dataRows.sort((a,b) => a[1].localeCompare(b[1]));

      const ws = XLSX.utils.aoa_to_sheet([header, ...dataRows]);

      /* column widths */
      ws['!cols'] = [
        {wch:16},  // Student ID
        {wch:26},  // Name
        {wch:28},  // Course Unit
        ...allDates.map(()=>({wch:12})),  // date columns
        {wch:14},  // Days Present
        {wch:14},  // Attendance %
      ];

      /* freeze top row + first 3 columns */
      ws['!freeze'] = { xSplit:3, ySplit:1, topLeftCell:'D2', activePane:'bottomRight' };

      XLSX.utils.book_append_sheet(wb, ws, 'Attendance Matrix');

      /* ── SHEET 2: Raw Records ── */
      const rawRows = [
        ['Session', 'Date', 'Student ID', 'Name', 'Course Unit', 'Time In'],
        ...recs.map(r => [r.session, r.date, r.studentId, r.name, r.course, r.time])
      ];
      const wsRaw = XLSX.utils.aoa_to_sheet(rawRows);
      wsRaw['!cols'] = [{wch:20},{wch:12},{wch:16},{wch:26},{wch:28},{wch:10}];
      XLSX.utils.book_append_sheet(wb, wsRaw, 'Raw Records');

      /* ── SHEET 3: Summary ── */
      const summaryRows = [
        ['FaceTrack Semester Attendance Report'],
        [],
        ['Period',           `${expFrom}  to  ${expTo}`],
        ['Session Filter',   expSession === 'all' ? 'All Sessions' : expSession],
        ['Generated On',     new Date().toLocaleString()],
        [],
        ['Total Records',    expPreview.total],
        ['Unique Students',  expPreview.unique_students],
        ['Class Days',       allDates.length],
        ['Sessions Covered', expPreview.sessions_covered.join(', ')],
        [],
        ['Date', 'Students Present'],
        ...allDates.map(d => [d, recs.filter(r=>r.date===d).length]),
      ];
      const wsSummary = XLSX.utils.aoa_to_sheet(summaryRows);
      wsSummary['!cols'] = [{wch:30},{wch:40}];
      XLSX.utils.book_append_sheet(wb, wsSummary, 'Summary');

      /* ── Write file ── */
      const filename = `Attendance_${expFrom}_to_${expTo}.xlsx`;
      XLSX.writeFile(wb, filename);
      showToast(`✓ Excel downloaded! ${expPreview.unique_students} students × ${allDates.length} days`);

    } catch(e) {
      showToast('Export failed: '+e.message,'error');
    } finally { setExpLoading(false); }
  };

  /* ── RENDER ── */
  return (
    <div className="page-wide">
      <h1 className="page-title">Attendance Records</h1>
      <p className="page-sub">View daily logs or export a full semester report as Excel.</p>

      <div style={{display:'flex',gap:8,marginBottom:24}}>
        <button className={`btn ${!showExport?'btn-primary':'btn-secondary'}`} onClick={()=>setShowExport(false)}>📅 Daily View</button>
        <button className={`btn ${showExport?'btn-primary':'btn-secondary'}`}  onClick={()=>setShowExport(true)}>📊 Semester Export</button>
      </div>

      {/* ══ DAILY VIEW ══ */}
      {!showExport && (<>
        <div style={{display:'flex',gap:12,alignItems:'center',marginBottom:24,flexWrap:'wrap'}}>
          <div style={{display:'flex',alignItems:'center',gap:8}}>
            <label style={{fontSize:'.8rem',color:'var(--text2)',fontWeight:600}}>SESSION</label>
            <select value={session} onChange={e=>setSession(e.target.value)}
              style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:10,padding:'8px 12px',color:'var(--text)',fontFamily:'var(--font)',fontSize:'.9rem',outline:'none'}}>
              <option value="default">default</option>
              {sessions.filter(s=>s!=='default').map(s=><option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div style={{display:'flex',alignItems:'center',gap:8}}>
            <label style={{fontSize:'.8rem',color:'var(--text2)',fontWeight:600}}>DATE</label>
            <input type="date" value={selectedDate} onChange={e=>setSelectedDate(e.target.value)}
              style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:10,padding:'8px 12px',color:'var(--text)',fontFamily:'var(--font)',fontSize:'.9rem',outline:'none'}} />
          </div>
          <button className="btn btn-secondary" onClick={exportDailyCSV} disabled={!records.length} style={{marginLeft:'auto'}}>⬇ Export CSV</button>
        </div>

        <div className="stats">
          <div className="stat"><div className="stat-val">{records.length}</div><div className="stat-lbl">Present</div></div>
          <div className="stat"><div className="stat-val" style={{color:'var(--accent)',fontSize:16,paddingTop:6}}>{session}</div><div className="stat-lbl">Session</div></div>
          <div className="stat"><div className="stat-val" style={{color:'var(--yellow)',fontSize:16,paddingTop:6}}>{selectedDate}</div><div className="stat-lbl">Date</div></div>
        </div>

        <div className="panel">
          {loading ? (
            <p style={{textAlign:'center',color:'var(--text2)',padding:'40px 0'}}>Loading…</p>
          ) : records.length===0 ? (
            <p style={{textAlign:'center',color:'var(--text2)',padding:'40px 0'}}>No records for this session and date.</p>
          ) : (
            <div className="table-wrap">
              <table>
                <thead><tr><th>#</th><th>Student ID</th><th>Name</th><th>Course Unit</th><th>Time</th><th>Status</th></tr></thead>
                <tbody>
                  {records.map((r,i)=>(
                    <tr key={i}>
                      <td style={{color:'var(--text3)',fontSize:'.8rem'}}>{String(i+1).padStart(2,'0')}</td>
                      <td><span className="mono">{r.studentId}</span></td>
                      <td style={{fontWeight:500}}>{r.name}</td>
                      <td><span className="tag">{r.course}</span></td>
                      <td style={{color:'var(--text2)',fontSize:'.85rem',fontFamily:'monospace'}}>{r.time}</td>
                      <td><span className="badge badge-present">✓ Present</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </>)}

      {/* ══ SEMESTER EXPORT ══ */}
      {showExport && (
        <div>
          <div className="panel">
            <div className="panel-title">📊 Semester / Date Range Export</div>

            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:16,marginBottom:16}}>
              <div className="form-group" style={{marginBottom:0}}>
                <label>From Date</label>
                <input type="date" value={expFrom} onChange={e=>setExpFrom(e.target.value)} />
              </div>
              <div className="form-group" style={{marginBottom:0}}>
                <label>To Date</label>
                <input type="date" value={expTo} onChange={e=>setExpTo(e.target.value)} />
              </div>
              <div className="form-group" style={{marginBottom:0}}>
                <label>Session / Course Unit</label>
                <select value={expSession} onChange={e=>setExpSession(e.target.value)}>
                  <option value="all">All Sessions</option>
                  {sessions.map(s=><option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>

            {/* Quick picks */}
            <div style={{display:'flex',gap:8,flexWrap:'wrap',marginBottom:20}}>
              {[
                {label:'This Month',    fn:()=>{ const n=new Date(); setExpFrom(n.toISOString().slice(0,8)+'01'); setExpTo(n.toISOString().slice(0,10)); }},
                {label:'Last 3 Months',fn:()=>{ const n=new Date(),f=new Date(n); f.setMonth(f.getMonth()-3); setExpFrom(f.toISOString().slice(0,10)); setExpTo(n.toISOString().slice(0,10)); }},
                {label:'Sem 1 Jan–Jun', fn:()=>{ const y=new Date().getFullYear(); setExpFrom(`${y}-01-01`); setExpTo(`${y}-06-30`); }},
                {label:'Sem 2 Jul–Dec', fn:()=>{ const y=new Date().getFullYear(); setExpFrom(`${y}-07-01`); setExpTo(`${y}-12-31`); }},
                {label:'Full Year',     fn:()=>{ const y=new Date().getFullYear(); setExpFrom(`${y}-01-01`); setExpTo(`${y}-12-31`); }},
              ].map(({label,fn})=>(
                <button key={label} className="btn btn-secondary" style={{padding:'6px 14px',fontSize:'.82rem'}} onClick={fn}>{label}</button>
              ))}
            </div>

            <div style={{display:'flex',gap:10}}>
              <button className="btn btn-purple" onClick={loadPreview} disabled={expLoading||!expFrom||!expTo} style={{flex:1,justifyContent:'center'}}>
                {expLoading ? '⏳ Loading…' : '🔍 Preview'}
              </button>
              {expPreview?.records?.length>0 && (
                <button className="btn btn-primary" onClick={exportExcel} disabled={expLoading} style={{flex:1,justifyContent:'center'}}>
                  {expLoading ? '⏳ Generating…' : '📥 Download Excel (.xlsx)'}
                </button>
              )}
            </div>
          </div>

          {/* What the Excel looks like */}
          <div className="panel" style={{background:'rgba(124,106,247,0.06)',border:'1px solid rgba(124,106,247,0.2)',marginBottom:0}}>
            <div className="panel-title" style={{color:'var(--purple)'}}>📋 Excel Sheet Structure</div>
            <div style={{overflowX:'auto'}}>
              <table style={{fontSize:'.8rem',color:'var(--text2)',borderCollapse:'collapse',width:'100%'}}>
                <thead>
                  <tr style={{color:'var(--text3)'}}>
                    <th style={{padding:'6px 10px',borderBottom:'1px solid var(--border)',textAlign:'left'}}>Student ID</th>
                    <th style={{padding:'6px 10px',borderBottom:'1px solid var(--border)',textAlign:'left'}}>Name</th>
                    <th style={{padding:'6px 10px',borderBottom:'1px solid var(--border)',textAlign:'left'}}>Course Unit</th>
                    {['Apr-01','Apr-02','Apr-03','Apr-04','…'].map(d=>(
                      <th key={d} style={{padding:'6px 10px',borderBottom:'1px solid var(--border)',textAlign:'center',color:'var(--purple)'}}>{d}</th>
                    ))}
                    <th style={{padding:'6px 10px',borderBottom:'1px solid var(--border)',textAlign:'center'}}>Days</th>
                    <th style={{padding:'6px 10px',borderBottom:'1px solid var(--border)',textAlign:'center'}}>%</th>
                  </tr>
                </thead>
                <tbody>
                  {[
                    {id:'CS/001',name:'Jane Kamau',     course:'Software Engineering', ticks:[1,1,0,1]},
                    {id:'CS/002',name:'John Mwangi',    course:'Software Engineering', ticks:[1,0,1,1]},
                    {id:'CS/003',name:'Alice Wanjiru',  course:'Software Engineering', ticks:[0,1,1,0]},
                  ].map(s=>(
                    <tr key={s.id}>
                      <td style={{padding:'6px 10px',fontFamily:'monospace',color:'var(--accent)'}}>{s.id}</td>
                      <td style={{padding:'6px 10px',fontWeight:500,color:'var(--text)'}}>{s.name}</td>
                      <td style={{padding:'6px 10px'}}>{s.course}</td>
                      {[...s.ticks,'…'].map((t,i)=>(
                        <td key={i} style={{padding:'6px 10px',textAlign:'center',color:'var(--success)',fontSize:'1rem'}}>{t===1?'✓':t==='…'?'…':''}</td>
                      ))}
                      <td style={{padding:'6px 10px',textAlign:'center',color:'var(--text)'}}>{s.ticks.filter(Boolean).length}</td>
                      <td style={{padding:'6px 10px',textAlign:'center',color:'var(--accent)'}}>{Math.round(s.ticks.filter(Boolean).length/s.ticks.length*100)}%</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <p style={{fontSize:'.78rem',color:'var(--text3)',marginTop:12}}>↑ Preview of the Excel matrix. Each column = one class day. ✓ = present. Blank = absent.</p>
          </div>

          {/* Preview results */}
          {expPreview && expPreview.records.length > 0 && (
            <>
              <div className="stats" style={{marginTop:16}}>
                <div className="stat"><div className="stat-val">{expPreview.unique_students}</div><div className="stat-lbl">Students</div></div>
                <div className="stat"><div className="stat-val" style={{color:'var(--accent)'}}>{[...new Set(expPreview.records.map(r=>r.date))].length}</div><div className="stat-lbl">Class Days</div></div>
                <div className="stat"><div className="stat-val" style={{color:'var(--purple)'}}>{expPreview.total}</div><div className="stat-lbl">Total Records</div></div>
              </div>

              <div className="panel">
                <div className="panel-title">
                  Preview — {expPreview.total} records
                  <span style={{marginLeft:'auto',fontSize:12,color:'var(--text3)'}}>{expPreview.date_from} → {expPreview.date_to}</span>
                </div>
                <div className="table-wrap" style={{maxHeight:300,overflowY:'auto'}}>
                  <table>
                    <thead><tr><th>Session</th><th>Date</th><th>Student ID</th><th>Name</th><th>Course Unit</th><th>Time</th></tr></thead>
                    <tbody>
                      {expPreview.records.map((r,i)=>(
                        <tr key={i}>
                          <td><span className="tag">{r.session}</span></td>
                          <td style={{fontFamily:'monospace',fontSize:'.85rem'}}>{r.date}</td>
                          <td><span className="mono">{r.studentId}</span></td>
                          <td style={{fontWeight:500}}>{r.name}</td>
                          <td style={{color:'var(--text2)'}}>{r.course}</td>
                          <td style={{fontFamily:'monospace',fontSize:'.85rem',color:'var(--text2)'}}>{r.time}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </>
          )}

          {expPreview && expPreview.records.length === 0 && (
            <div className="panel" style={{textAlign:'center',color:'var(--text2)',padding:'40px'}}>
              No records found for this date range and session.
            </div>
          )}
        </div>
      )}

      {toast && <div className={`toast ${toast.type}`} onClick={()=>setToast(null)}>{toast.msg}</div>}
    </div>
  );
}
